import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

/**
 * Tests for issue: False positive indent after updating from 0.47.1
 * https://github.com/pinterest/ktlint/issues/1888
 *
 * When DOT_QUALIFIED_EXPRESSION and SAFE_ACCESS_EXPRESSION are mixed in a chain,
 * only one indent context should be created for the entire chain.
 */
internal class IndentationRuleMixedChainTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Nested
    inner class `Given a mixed chain of dot qualified and safe access expressions` {
        @Test
        fun `Issue 1888 - Given a function with expression body containing runCatching followed by safe access`() {
            val code =
                """
                private fun test(): Boolean? =
                    runCatching { true }
                        .getOrNull()?.let { result ->
                            !result
                        }
                """.trimIndent()
            indentationRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a property with mixed chain of dot qualified followed by safe access expressions`() {
            val code =
                """
                val foo = bar
                    .doSomething()?.let { result ->
                        result.process()
                    }
                """.trimIndent()
            indentationRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a property with mixed chain of safe access followed by dot qualified expressions`() {
            val code =
                """
                val foo = bar
                    ?.doSomething().let { result ->
                        result.process()
                    }
                """.trimIndent()
            indentationRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a complex mixed chain`() {
            val code =
                """
                val result = someObject
                    .method1()
                    ?.method2()
                    .method3()?.let { value ->
                        value.transform()
                    }
                """.trimIndent()
            indentationRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a function with expression body and multiple mixed chain operations`() {
            val code =
                """
                fun process() =
                    getData()
                        .transform()
                        ?.validate()?.let { validData ->
                            validData.save()
                        }
                """.trimIndent()
            indentationRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given nested lambdas within mixed chain`() {
            val code =
                """
                val result = items
                    .map { item ->
                        item.value
                    }?.filter { value ->
                        value > 0
                    }
                """.trimIndent()
            indentationRuleAssertThat(code).hasNoLintViolations()
        }
    }
}
